queries.sparql:
PREFIX : <http://ambrosia.example.org/hospitality#>
PREFIX p: <http://ambrosia.example.org/hospitality/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?o0 WHERE {
  {
    ?buffet a :Buffet .
    ?buffet p:name ?name .
    ?buffet p:Hours ?hours_f .
    FILTER(STR(?hours_f) = "7.30 a.m. - 4 p.m.")
    BIND(?name AS ?o0)
  }
  UNION
  {
    ?coffee_shop a :Coffee_Shop .
    ?coffee_shop p:name ?name .
    ?coffee_shop p:Hours ?hours_f .
    FILTER(STR(?hours_f) = "7.30 a.m. - 4 p.m.")
    BIND(?name AS ?o0)
  }
}

